1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	interface Damage {
13	  itemType: string;
14	  amount: number;
15	}
16	
17	interface Incident {
18	  cause: string;
19	  damages: Damage[];
20	}
21	
22	interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: Incident;
26	}
