28	type Step = QuoteStep | ClaimStep;
29	
30	interface Scenario {
31	  customer: { yearsWithMHPCO: number };
32	  steps: Step[];
33	}
34	
35	const BASE_PREMIUM: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	};
41	
42	const COMPONENT_PREMIUM = 25;
43	const COMPONENT_BLOCK_SIZE = 3;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
46	
47	const INSURANCE_VALUE: Record<string, number> = {
48	  sword: 1000,
49	  amulet: 600,
50	  staff: 800,
51	  potion: 400,
52	};
53	const COMPONENT_INSURANCE_VALUE = 250;
54	
55	const DEDUCTIBLE = 100;
56	const CAP_MULTIPLIER = 2;
57	
58	const FIRST_INSURANCE_SURCHARGE = 1.1;
59	const CURSE_SURCHARGE_RATE = 0.5;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
62	const LOYALTY_THRESHOLD_YEARS = 2;
63	const LOYALTY_DISCOUNT_RATE = 0.2;
64	const FOLLOWUP_DISCOUNT_RATE = 0.15;
65	const PROCESSING_FEE = 5;
66	
67	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
68	
69	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
70	
71	// Base premium of a single item (main item or one component).
72	const itemBase = (item: Item): number =>
73	  isComponent(item) ? COMPONENT_PREMIUM : (BASE_PREMIUM[item.type] ?? 0);
74	
75	// A surcharge adds `rate` of the base premium for each affected item.
76	const surchargeFor = (items: Item[], affects: (item: Item) => boolean, rate: number): number =>
77	  sum(items.filter(affects).map((item) => rate * itemBase(item)));
78	
79	// Curse adds 50% of the affected item's base premium.
80	const curseSurcharge = (items: Item[]): number =>
81	  surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
82	
83	// High enchantment (level >= 5) adds 30% of the affected item's base premium.
84	const enchantmentSurcharge = (items: Item[]): number =>
85	  surchargeFor(
86	    items,
87	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
88	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
89	  );
90	
91	// Base premium for `count` alike components: a group of exactly 3 forms a
92	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
93	// COMPONENT_PREMIUM.
94	const componentGroupPremium = (count: number): number =>
95	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
96	
97	// Count how many alike components of each type appear (e.g. { rune: 2 }).
98	const countByType = (items: Item[]): Map<string, number> =>
99	  items.reduce((counts, item) => {
100	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
101	    return counts;
102	  }, new Map<string, number>());
103	
104	const mainItemsPremium = (items: Item[]): number =>
105	  sum(items.filter((item) => !isComponent(item)).map(itemBase));
106	
107	const componentsPremium = (items: Item[]): number =>
108	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
109	
110	const basePremium = (items: Item[]): number =>
111	  mainItemsPremium(items) + componentsPremium(items);
112	
113	// Insurance value of a single item (main item or one component).
114	const insuranceValue = (item: Item): number =>
115	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : (INSURANCE_VALUE[item.type] ?? 0);
116	
117	// Round up to a whole number in MHPCO's favour, guarding against
118	// floating-point noise (e.g. 197.5000000001) before the ceiling by snapping
119	// to 6 decimal places first.
120	const FLOAT_GUARD_PRECISION = 1e6;
121	const roundUpToWhole = (value: number): number =>
122	  Math.ceil(Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION);
123	
124	// Round a payout down to whole G, in MHPCO's favour.
125	const roundDownToWhole = (value: number): number =>
126	  Math.floor(Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION);
127	
128	// A policy-wide discount takes `rate` of the policy base when it applies.
129	const discount = (applies: boolean, rate: number, base: number): number =>
130	  applies ? rate * base : 0;
131	
132	// Long-standing customers (>= 2 years) receive 20% off the policy base.
133	const loyaltyDiscount = (base: number, yearsWithMHPCO: number): number =>
134	  discount(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT_RATE, base);
135	
136	// Every quote after the customer's first receives 15% off the policy base.
137	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
138	  discount(isFollowUp, FOLLOWUP_DISCOUNT_RATE, base);
139	
140	// Premium for one quote: base premium plus the first-insurance surcharge,
141	// item-specific curse/enchantment surcharges, less the policy-wide loyalty
142	// and follow-up discounts, and the flat processing fee.
143	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
144	  const base = basePremium(items);
145	  return (
146	    base * FIRST_INSURANCE_SURCHARGE +
147	    curseSurcharge(items) +
148	    enchantmentSurcharge(items) -
149	    loyaltyDiscount(base, yearsWithMHPCO) -
150	    followUpDiscount(base, isFollowUp) +
151	    PROCESSING_FEE
152	  );
153	};
154	
155	// Payout for one damage event: full reimbursement less the per-event deductible.
156	const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);
157	
158	// Result of claiming against a policy: total payout (capped) and remaining cap.
159	const claimResult = (policy: Item[], incident: Incident): { payout: number; remainingCap: number } => {
160	  const cap = CAP_MULTIPLIER * sum(policy.map(insuranceValue));
161	  const payout = roundDownToWhole(sum(incident.damages.map(damagePayout)));
162	  return { payout, remainingCap: cap - payout };
163	};
164	
165	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
166	  const { yearsWithMHPCO } = scenario.customer;
167	  const policyItemsByStep: Record<number, Item[]> = {};
168	  let quotesSeen = 0;
169	  const results = scenario.steps.map((step, index) => {
170	    if (step.op === "claim") {
171	      return claimResult(policyItemsByStep[step.policy], step.incident);
172	    }
173	    const isFollowUp = quotesSeen > 0;
174	    quotesSeen += 1;
175	    policyItemsByStep[index] = step.items;
176	    return { premium: roundUpToWhole(quotePremium(step.items, yearsWithMHPCO, isFollowUp)) };
177	  });
178	  return { results };
179	};
